def icon(name, cls='', size=None):
    f = _MAP.get(name, 'dot')
    st = (' style="width:%s;height:%s"' % (size, size)) if size else ''
    c = ('ic ' + cls).strip()
    return '<svg class="%s"%s aria-hidden="true"><use href="#i-%s"></use></svg>' % (c, st, f)
